  "studentLessonNotes": {
    "title": "Alcohols, Phenols & Ethers: Session 1 - Introduction",
    "introduction": "Welcome to the world of oxygenated hydrocarbons! In this session, we meet two very important families: Alcohols and Phenols. While they both contain an -OH group (hydroxyl), their behavior is surprisingly different because of where that group sits.",
    "learningObjectives": [
      "Distinguish between aliphatic (-OH on alkane) and aromatic (-OH on benzene) compounds.",
      "Apply IUPAC rules to name simple alcohols and phenols.",
      "Understand the basic structural difference leading to different properties."
    ],
    "quickRecall": [
      "Alkanes: Saturated hydrocarbons (C-C single bonds).",
      "Benzene: A stable aromatic ring with alternating double bond character.",
      "Functional Group: The reactive part of a molecule (-OH)."
    ],
    "sections": [
      {
        "heading": "What are Alcohols?",
        "explanation": "Alcohols are organic compounds where the hydroxyl group (-OH) is attached to an aliphatic carbon atom (a saturated carbon chain or ring). Think of them as 'alkanes with a tail'.",
        "keyPoints": [
          "General Formula: R-OH (where R = alkyl group)",
          "Carbon holding -OH is sp3 hybridized.",
          "Examples: Ethanol, Methanol."
        ],
        "examples": [
          "Ethanol: CH3-CH2-OH",
          "Isopropyl Alcohol: (CH3)2CH-OH"
        ],
        "whyItMatters": "They are excellent solvents and the basis for many chemical syntheses.",
        "terminology": [
          "Aliphatic carbon",
          "Hydroxyl group"
        ],
        "detailedExplanation": "The -OH group makes alcohols polar. This allows them to form hydrogen bonds with water, making small alcohols soluble in water and giving them higher boiling points than hydrocarbons of similar mass.",
        "observedIn": [
          "Rubbing alcohol",
          "Hand sanitizers"
        ],
        "visualSupport": [
          "Diagram showing R-OH with a chain."
        ],
        "importantNotes": [
          "Do not confuse 'alcohol' (the class) with the beverage ethanol specifically.",
          "The carbon attached to OH determines if it is primary, secondary, or tertiary."
        ],
        "memoryTechniques": [
          "'Aliphatic = Alkane-like chain'"
        ],
        "conceptSummary": [
          "-OH on a saturated carbon chain/ring."
        ]
      },
      {
        "heading": "What are Phenols?",
        "explanation": "Phenols are distinct from alcohols. In phenols, the -OH group is directly attached to an aromatic benzene ring.",
        "keyPoints": [
          "General Formula: Ar-OH (where Ar = aryl/benzene ring)",
          "Carbon holding -OH is sp2 hybridized and part of the ring.",
          "Examples: Phenol, Cresols."
        ],
        "examples": [
          "Phenol: C6H5-OH",
          "o-Cresol (Methylphenol)"
        ],
        "whyItMatters": "They are used in antiseptics and plastics. Their acidity is different from alcohols.",
        "terminology": [
          "Aromatic ring",
          "Direct attachment"
        ],
        "detailedExplanation": "Because the -OH is attached to a benzene ring, the electrons interact differently with the ring system (resonance). This makes phenols chemically unique compared to alcohols.",
        "observedIn": [
          "Carbolic acid",
          "Disinfectants"
        ],
        "visualSupport": [
          "Diagram of a hexagon with -OH attached directly."
        ],
        "importantNotes": [
          "Phenol is NOT an alcohol in the strict chemical classification, though they share the -OH group.",
          "The carbon holding OH cannot be part of a double bond outside the ring system for it to be phenol; it must be IN the aromatic ring."
        ],
        "memoryTechniques": [
          "'Phenol = Phenyl (Benzene) + Ol'"
        ],
        "conceptSummary": [
          "-OH directly bonded to a benzene ring."
        ]
      }
    ],
    "definitions": [
      {
        "term": "Alcohol",
        "definition": "Compound with -OH attached to an aliphatic carbon (sp3)."
      },
      {
        "term": "Phenol",
        "definition": "Compound with -OH directly attached to a benzene ring (aromatic, sp2)."
      }
    ],
    "workedExamples": [
      {
        "title": "Naming an Alcohol: Propan-1-ol",
        "steps": [
          "Identify the longest carbon chain containing -OH.",
          "Number from the end closest to -OH (gives it position 1).",
          "Name as 'alkane' + '-ol', dropping the final 'e'.",
          "Add locant number if needed."
        ],
        "explanation": "Chain is 3 carbons -> Propane. Drop 'e', add 'ol' -> Propanol. OH is at C1 -> Propan-1-ol."
      },
      {
        "title": "Identifying Phenol",
        "steps": [
          "Look for a benzene ring (hexagon with circle or alternating bonds).",
          "Check if -OH is attached directly to the hexagon.",
          "If yes, it's a phenol derivative."
        ],
        "explanation": "Structure C6H5-OH has OH on the ring. It is Phenol. If there was an ethyl group between the ring and OH (C2H4-C6H5-OH), it would be an alcohol, not a phenol."
      }
    ],
